def spaghetti_sort(arr):
	max_val = max(arr)
	poles = [0] * (max_val + 1)
	for num in arr:
		poles[num] += 1
	res = []
	for i in range(len(poles)):
		while poles[i] > 0:
			res.append(i)
			poles[i] -= 1
	return res

Code.JavaScript:
function spaghettiSort(arr) {
	let max = Math.max(...arr);
	let poles = new Array(max + 1).fill(0);
	for (let i = 0; i < arr.length; i++) {
		poles[arr[i]]++;
	}
	let res = [];
	for (let i = 0; i < poles.length; i++) {
		while (poles[i] > 0) {
			res.push(i);
			poles[i]--;
		}
	}
	return res;
}

