void spaghettiSort(int arr[], int n) {
	int max = arr[0];
	for (int i = 1; i < n; i++) {
		if (arr[i] > max) max = arr[i];
	}
	int *poles = (int *)calloc(max + 1, sizeof(int));
	for (int i = 0; i < n; i++) {
		poles[arr[i]]++;
	}
	int index = 0;
	for (int i = 0; i <= max; i++) {
		while (poles[i] > 0) {
			arr[index++] = i;
			poles[i]--;
		}
	}
	free(poles);
}
